checker_dsl:
EXISTS (`expression E`) {
  AND {
    EXISTS (`variable V`) {
      EXISTS (`reference type T`) {
        EXISTS (`reference type SUP`) {
          EXISTS (`expression COND`) {
            AND {
              EXISTS (`SSA definition SSA`) {
                AND {
                  (`SSA's source variable is V`),
                  EXISTS (`variable access VA`) {
                    AND {
                      (`VA is a read of SSA`),
                      OR {
                        AND {
                          (`E is a CastExpr`),
                          (`E's cast expression is VA`),
                          (`E's type is a reference type`),
                          (`the source declaration of E's type is T`)
                        },
                        AND {
                          (`E is an InstanceOfExpr`),
                          (`E's checked expression is VA`),
                          (`E's checked type is a reference type`),
                          (`the source declaration of E's checked type is T`)
                        }
                      }
                    }
                  },
                  (`SUP is an ancestor of T`),
                  (`COND is an InstanceOfExpr`),
                  (`COND's checked expression is VA`),
                  (`COND's checked type is a reference type`),
                  (`the source declaration of COND's checked type is SUP`),
                  (`COND as a Guard controls the basic block containing E on the false edge`)
                }
              }
            }
          }
        }
      }
    }
  }
}
